ll
 n;
ll dp[105][32][32][32];
ll fn(ll i,ll p,ll q,ll r)
{
    if(i>=n)
    {
        if(p==0 and q==0 and r==0)
            return 0;

        return mod;
    }

    if(dp[i][p][q][r]!=-1)return dp[i][p][q][r];

    ll ans=inf;

    //either don't do anything
    ans=fn(i+1,p,q,r);

    // taking array of len=1
    if(p>0)
    ans=min(ans,a[i]+fn(i+2,p-1,q,r));


    //taking array of len=2
    if(q>0 and i+1<n)
    ans=min(ans,a[i]+a[i+1]+fn(i+3,p,q-1,r));

    //taking array of len=3
    if(r>0 and i+2<n)
    ans=min(ans,a[i]+a[i+1]+a[i+2]+fn(i+4,p,q,r-1));

    return dp[i][p][q][r]=ans;

}

